import React from "react";
import { Link } from "react-router-dom";

const Menu = () => {
  return (
    <nav>
      <Link to="/">Головна</Link>
      <Link to="/events">Події</Link>
      <Link to="/news">Новини</Link>
      <Link to="/about">Про нас</Link>
    </nav>
  );
};

export default Menu;
